import axios from 'axios';

const API_URL =
  'http://localhost:8080/api/resume';

const AUTH_URL =
  'http://localhost:8080/api/auth';

// TOKEN HEADER

const getAuthHeader = () => {

  const token =
    localStorage.getItem('token');

  if (!token) {

    return {};
  }

  return {

    headers: {

      Authorization:
        `Bearer ${token}`
    }
  };
};

class ResumeService {

  // ================= AUTH =================

  register(user) {

    return axios.post(

      `${AUTH_URL}/register`,

      user
    );
  }

  login(user) {

    return axios.post(

      `${AUTH_URL}/login`,

      user
    );
  }

  // ================= CRUD =================

  getAllResumes() {

    return axios.get(

      API_URL,

      getAuthHeader()
    );
  }

  saveResume(resume) {

    return axios.post(

      API_URL,

      resume,

      getAuthHeader()
    );
  }

  getResumeById(id) {

    return axios.get(

      `${API_URL}/${id}`,

      getAuthHeader()
    );
  }

  updateResume(id, resume) {

    return axios.put(

      `${API_URL}/${id}`,

      resume,

      getAuthHeader()
    );
  }

  deleteResume(id) {

    return axios.delete(

      `${API_URL}/${id}`,

      getAuthHeader()
    );
  }

  // ================= AI =================

  generateSummary(skills) {

    return axios.post(

      `${API_URL}/generate-summary`,

      skills,

      {

        headers: {

          'Content-Type':
            'text/plain',

          Authorization:
            `Bearer ${localStorage.getItem('token')}`
        }
      }
    );
  }
}

export default new ResumeService();
